function initAudioPlayer() {
    if (!currentAudioElement) {
        currentAudioElement = new Audio();
    }
    if (!audioContext) {
        try {
            audioContext = new (window.AudioContext || window.webkitAudioContext)();
            audioAnalyser = audioContext.createAnalyser();
            audioAnalyser.fftSize = 64;
            audioSourceNode = audioContext.createMediaElementSource(currentAudioElement);
            audioSourceNode.connect(audioAnalyser);
            audioAnalyser.connect(audioContext.destination);
        } catch (e) {
            console.warn("Web Audio API hook failed:", e);
        }
    }
    if (audioContext && audioContext.state === 'suspended') {
        audioContext.resume();
    }
}

function formatTitleHTML(title) {
    if (!title) return '';
    // Match common prefixes to separate them into small header lines (including Thảm họa, Tác hại, Giải pháp, v.v.)
    const match = title.match(/^(Khắc phục(?:\s+\d+)?|Thảm họa|Tác hại|Giải pháp|Kết quả|Hậu quả|Nguyên lý|Trước tối ưu|Sau tối ưu|Bí ẩn|Câu hỏi|Thắc mắc|Tại sao|So sánh|Khởi đầu|Dữ liệu đầu vào|Chu kỳ thời gian|Cơ chế bảo mật|Kết quả băm|Rút gọn số|Cắt lấy 6 số|Xác thực khớp mã|Tâm lý lệch giờ|Mất deal vì|Hạ tầng SMS|Giải pháp offline|Bí ẩn đằng sau|Xác thực|Khóa bí mật|Thời gian|Chu kỳ|Thuật toán|Cắt số|Lệch giờ|Nguyên nhân|Cơ chế|Gửi Request|Ghi nhận|Giao tiếp|Xử lý|Hoàn thành|Lỗi mạng|Thử lại)[:\-\.]?\s*(.*)$/i);
    if (match) {
        let mainText = match[2] || '';
        if (mainText) {
            mainText = mainText.charAt(0).toUpperCase() + mainText.slice(1);
        }
        return `<span class="title-prefix">${match[1]}</span><span class="title-main">${mainText}</span>`;
    }
    return title;
}

function getPerformanceStatus(slide) {
    if (!slide) return { text: 'Performance Boosted!', class: 'success', icon: 'sparkles' };
    
    if (slide.badge) {
        if (slide.badge.type === 'danger' || slide.badge.type === 'warning') {
            return { text: slide.badge.text || 'Performance Warning', class: slide.badge.type, icon: slide.badge.icon || 'alert-triangle' };
        }
        return { text: slide.badge.text || 'Performance Boosted!', class: 'success', icon: slide.badge.icon || 'sparkles' };
    }
    
    const combined = `${slide.title || ''} ${slide.subtitle || ''} ${slide.id || ''}`.toLowerCase();
    
    if (combined.includes('thiếu an toàn') || 
        combined.includes('thủ phạm') || 
        combined.includes('lỗ hổng') || 
        combined.includes('nguy hiểm') || 
        combined.includes('hacker') || 
        combined.includes('tấn công') || 
        combined.includes('danger')) {
        return { text: 'Security Vulnerability!', class: 'danger', icon: 'alert-octagon' };
    }
    
    if (combined.includes('trước tối ưu') || 
        combined.includes('chậm') || 
        combined.includes('chưa') || 
        combined.includes('scan') || 
        combined.includes('tuần tự') || 
        combined.includes('nghẽn') || 
        combined.includes('hậu quả') ||
        combined.includes('tác hại')) {
        return { text: 'Performance Warning!', class: 'danger', icon: 'alert-triangle' };
    }
    
    return { text: 'Performance Boosted!', class: 'success', icon: 'sparkles' };
}

function initVisualizerBars(numBars = 40) {
    const container = document.querySelector('.visualizer-container');
    if (!container) return;
    container.innerHTML = '';
    for (let i = 0; i < numBars; i++) {
        const bar = document.createElement('div');
        bar.className = `visualizer-bar bar-${i + 1}`;
        container.appendChild(bar);
    }
    visualizerBars = null; // Clear cached array to trigger re-query
}

// Estimate slide duration based on script text or generated audio

function getSlideDuration(slide) {
    if (!slide) return 10.0;
    if (slide.audioPath && slide.duration) {
        return slide.duration;
    }
    // Fallback calculation based on script text length
    const words = (slide.script || '').trim().split(/\s+/).filter(w => w.length > 0);
    if (words.length > 0) {
        // Estimate average reading speed: 2.5 words per second
        return Math.min(30.0, Math.max(4.0, words.length / 2.5));
    }
    return 10.0;
}

function getSlideIcon(slide) {
    if (!slide) return "heading";
    if (slide.icon) return slide.icon;
    
    const titleLower = (slide.title || "").toLowerCase();
    const subtitleLower = (slide.subtitle || "").toLowerCase();
    const combined = `${titleLower} ${subtitleLower}`;
    
    if (combined.includes("database") || combined.includes("db") || combined.includes("bản ghi") || combined.includes("truy vấn")) {
        return "database";
    }
    if (combined.includes("chậm") || combined.includes("quá tải") || combined.includes("nghẽn") || combined.includes("lag") || combined.includes("lỗi") || combined.includes("timeout") || combined.includes("hậu quả")) {
        return "alert-triangle";
    }
    if (combined.includes("nhanh") || combined.includes("gấp") || combined.includes("tối ưu") || combined.includes("hiệu năng") || combined.includes("tốc độ") || combined.includes("lợi") || combined.includes("chỉ với") || combined.includes("eager")) {
        return "zap";
    }
    if (combined.includes("khắc phục") || combined.includes("giải pháp") || combined.includes("join") || combined.includes("load")) {
        return "check-circle";
    }
    if (combined.includes("so sánh")) {
        return "bar-chart-2";
    }
    
    if (slide.layout === 'code') return "code-2";
    if (slide.layout === 'diagram') return "git-commit";
    if (slide.layout === 'cards') return "layout-grid";
    if (slide.layout === 'metrics') return "trending-up";
    if (slide.layout === 'spotify') return "music";
    return "heading";
}

function getSlideHeaderEmoji(slide) {
    if (!slide) return '💡';
    if (slide.id && slide.id.startsWith('slide_ticket_1a')) {
        return '🎫';
    }
    const titleLower = (slide.title || "").toLowerCase();
    const subtitleLower = (slide.subtitle || "").toLowerCase();
    const combined = `${titleLower} ${subtitleLower}`;
    
    if (combined.includes("database lock") || combined.includes("db lock") || combined.includes("khóa")) {
        return "🔒";
    }
    if (combined.includes("redis decr") || combined.includes("redis lua")) {
        return "⚡";
    }
    if (combined.includes("sập") || combined.includes("nghẽn") || combined.includes("quá tải") || combined.includes("timeout") || combined.includes("lốt") || combined.includes("lỗi") || combined.includes("giành giật")) {
        return "💥";
    }
    if (combined.includes("database") || combined.includes("db") || combined.includes("ghi đè")) {
        return "💾";
    }
    if (combined.includes("thanh toán") || combined.includes("hàng đợi") || combined.includes("bất đồng bộ")) {
        return "💳";
    }
    if (combined.includes("tính tắc") || combined.includes("milli-giây") || combined.includes("tích tắc")) {
        return "⏱️";
    }
    if (combined.includes("theo dõi") || combined.includes("cảm ơn")) {
        return "🎉";
    }
    
    // Fallback based on layout
    if (slide.layout === 'code') return "💻";
    if (slide.layout === 'diagram') return "🎯";
    if (slide.layout === 'cards') return "🎴";
    if (slide.layout === 'metrics') return "📊";
    if (slide.layout === 'spotify') return "🎵";
    return "💡";
}

function getCardType(card) {
    if (!card) return "neutral";
    if (card.type === 'success' || card.type === 'pro') return 'pro';
    if (card.type === 'danger' || card.type === 'con') return 'con';
    if (card.type) return card.type;
    
    const combined = `${card.title || ""} ${card.desc || ""}`.toLowerCase();
    if (combined.includes("chậm") || combined.includes("tốn") || combined.includes("quá tải") || combined.includes("lag") || combined.includes("lỗi") || combined.includes("n+1") || combined.includes("timeout") || combined.includes("nghẽn") || combined.includes("sập")) {
        return "con";
    }
    if (combined.includes("nhanh") || combined.includes("tối ưu") || combined.includes("tiết kiệm") || combined.includes("join") || combined.includes("eager") || combined.includes("mượt")) {
        return "pro";
    }
    return "neutral";
}

